/// {@category Misc}
library;

// Flutter imports:
import 'package:flutter/widgets.dart';

// Package imports:
import 'package:fimber/fimber.dart';

class NavigationLogger extends NavigatorObserver {
  /// A set of route names not to be logged. The routes must be a return to the previous route.
  final Set<String>? ignoreRouteNames;

  late final FimberLog _logger;

  NavigationLogger({
    required String name,
    this.ignoreRouteNames,
  }) {
    _logger = FimberLog(name);
  }

  /// Checks if the route should be ignored based on its name.
  bool _shouldIgnoreRoute(Route? route) {
    // If the route.settings.name is null, it means the unknown route.
    // So it should be ignored.
    if (route?.settings.name == null) return true;

    // If the ignoreRouteNames is null, it means no route should be ignored.
    if (ignoreRouteNames == null) return false;

    // If the route.settings.name is in the ignoreRouteNames, it should be ignored.
    return ignoreRouteNames!.contains(route!.settings.name);
  }

  void _logRoute(
    String message,
    Route? route,
    Route? previousRoute, [
    bool logPrevious = false,
  ]) {
    if (_shouldIgnoreRoute(route) || _shouldIgnoreRoute(previousRoute)) {
      return;
    }

    // If route or previousRoute is null, it should be ignored and already returned.
    _logger
        .i('$message: ${_formatRoute(logPrevious ? previousRoute! : route!)}');
  }

  String _formatRoute(Route route) {
    final routeName = route.settings.name!;
    final arguments = route.settings.arguments != null
        ? ' (${route.settings.arguments})'
        : '';
    return '$routeName$arguments';
  }

  @override
  void didPush(Route route, Route? previousRoute) {
    _logRoute('navigated', route, previousRoute);
  }

  @override
  void didPop(Route route, Route? previousRoute) {
    _logRoute('navigated back', previousRoute, route);
  }

  @override
  void didRemove(Route route, Route? previousRoute) {
    _logRoute('removed route', previousRoute, route, true);
  }

  @override
  void didReplace({Route? newRoute, Route? oldRoute}) {
    _logRoute('replaced route', newRoute, oldRoute);
  }
}

