/// The entrypoint of this app.
///
/// This module
/// - Initializes Supabase client.
/// - Defines `ProviderScope` of `riverpod`.
/// - Initializes localization module.
/// - Setup debug modules.
///
/// {@category Misc}
// ignore_for_file: depend_on_referenced_packages

library;

// Dart imports:
import 'dart:async';

// Flutter imports:
import 'package:flutter/material.dart';
