          appRouterObserver,
          appRouterStreamer,
          _SplashPageObserver(
            onSplashPageLeft: () => _isOnSplashPage = false,
          ),
        ],
        navigatorKey: appRouterKey,
      ),
    );
  }

  void _handleMaintenanceState(
    MaintenanceState? previous,
    MaintenanceState next,
  ) {
    // メンテナンス開始
    if (next is InMaintenance && previous is! InMaintenance) {
      _isOnMaintenancePage = true;
      _isOnSplashPage = false;
      appRouterKey.currentState?.pushNamedAndRemoveUntil(
        AppRouter.maintenancePage,
        (_) => false,
      );
    }
    // メンテナンス終了
    else if (next is Operational && previous is InMaintenance) {
      _isOnMaintenancePage = false;
      _isOnSplashPage = true;
      appRouterKey.currentState?.pushNamedAndRemoveUntil(
        AppRouter.splashPage,
        (_) => false,
      );
    }
  }

  void _handleVersionState(VersionState? previous, VersionState next) {
    // メンテナンス中またはスプラッシュ画面中は更新通知を表示しない
    if (_isOnMaintenancePage || _isOnSplashPage) return;

    // 強制アップデート必要
    if (next is UpdateRequired && previous is! UpdateRequired) {
      _isOnSplashPage = false;
      appRouterKey.currentState?.pushNamedAndRemoveUntil(
        AppRouter.updateRequiredPage,
        (_) => false,
      );
    }
    // 任意アップデート可能（初回のみ表示）
    else if (next is UpdateAvailable &&
        previous is! UpdateAvailable &&
        previous is! UpdateRequired) {
      final context = appRouterKey.currentState?.context;
      if (context != null && context.mounted) {
        showDialog(
          context: context,
          barrierDismissible: true,
          routeSettings:
              const RouteSettings(name: AppRouter.updateAvailableDialog),
          builder: (dialogContext) {
            return UpdateAvailableDialog(
              currentVersion: next.currentVersion,
              latestVersion: next.latestVersion,
            );
          },
        );
      }
    }
    // 強制アップデート解除
    else if (next is UpToDate && previous is UpdateRequired) {
      _isOnSplashPage = true;
      appRouterKey.currentState?.pushNamedAndRemoveUntil(
        AppRouter.splashPage,
        (_) => false,
      );
    }
  }

